// give us the difference of two int arrays
// http://radu.cotescu.com/javascript-diff-function/
function arr_diff(a, b) {
  var seen = [],
      diff = [],
      i;
  for (i = 0; i < b.length; i++) {
    seen[b[i]] = true;
  }for (i = 0; i < a.length; i++) {
    if (!seen[a[i]]) diff.push(a[i]);
  }return diff;
}

MG.arr_diff = arr_diff;

